{
  "title": "Python for Beginners",
  "description": "A foundational course designed for youth to learn Python programming through text-first explanations and lightweight activities, suitable for offline-first connectivity.",
  "modules": [
    {
      "id": "module_1",
      "title": "Introduction to Python",
      "description": "Learn the basics of Python, including installation, syntax, and data types. Engage in simple exercises to familiarize yourself with writing and running Python code."
    },
    {
      "id": "module_2",
      "title": "Control Structures and Functions",
      "description": "Explore control structures such as loops and conditionals, and understand how to create and use functions in Python. Participate in hands-on activities to practice these concepts."
    },
    {
      "id": "module_3",
      "title": "Working with Data",
      "description": "Discover how to work with lists, dictionaries, and other data structures in Python. Complete lightweight tasks to manipulate and analyze data effectively."
    },
    {
      "id": "module_4",
      "title": "Introduction to Libraries and Simple Projects",
      "description": "Get introduced to popular Python libraries and apply your knowledge in small projects. Engage in guided activities that reinforce learning and encourage creativity."
    }
  ]
}
